#include "jni.h"
#include "com_test_Dlib.h"
#include <dlib/gui_widgets.h>
#include <dlib/clustering.h>
#include <dlib/string.h>
#include <dlib/dnn.h>
#include <dlib/image_io.h>
#include <dlib/image_processing/frontal_face_detector.h>

using namespace dlib;
using namespace std;


template <template <int, template<typename>class, int, typename> class block, int N, template<typename>class BN, typename SUBNET>
using residual = add_prev1<block<N, BN, 1, tag1<SUBNET>>>;

template <template <int, template<typename>class, int, typename> class block, int N, template<typename>class BN, typename SUBNET>
using residual_down = add_prev2<avg_pool<2, 2, 2, 2, skip1<tag2<block<N, BN, 2, tag1<SUBNET>>>>>>;

template <int N, template <typename> class BN, int stride, typename SUBNET>
using block = BN<con<N, 3, 3, 1, 1, relu<BN<con<N, 3, 3, stride, stride, SUBNET>>>>>;

template <int N, typename SUBNET> using ares = relu<residual<block, N, affine, SUBNET>>;
template <int N, typename SUBNET> using ares_down = relu<residual_down<block, N, affine, SUBNET>>;

template <typename SUBNET> using alevel0 = ares_down<256, SUBNET>;
template <typename SUBNET> using alevel1 = ares<256, ares<256, ares_down<256, SUBNET>>>;
template <typename SUBNET> using alevel2 = ares<128, ares<128, ares_down<128, SUBNET>>>;
template <typename SUBNET> using alevel3 = ares<64, ares<64, ares<64, ares_down<64, SUBNET>>>>;
template <typename SUBNET> using alevel4 = ares<32, ares<32, ares<32, SUBNET>>>;

using anet_type = loss_metric<fc_no_bias<128, avg_pool_everything<
	alevel0<
	alevel1<
	alevel2<
	alevel3<
	alevel4<
	max_pool<3, 3, 2, 2, relu<affine<con<32, 7, 7, 2, 2,
	input_rgb_image_sized<150>
	>>>>>>>>>>>>;



std::vector<matrix<rgb_pixel>> jitter_image(
	const matrix<rgb_pixel>& img
);


JNIEXPORT jboolean JNICALL Java_com_intple_test_Dlib_verify
(JNIEnv *env, jobject jobj, jstring path1, jstring path2, jstring landmark, jstring model, jdouble threshold)
{

	jboolean  result = false;
	try {
		const char* impath1 = NULL;
		const char* impath2 = NULL;
		const char* landmarks = NULL;
		const char* modelpath = NULL;	
		impath1 = (env)->GetStringUTFChars(path1, NULL);
		impath2 = (env)->GetStringUTFChars(path2, NULL);
		landmarks = (env)->GetStringUTFChars(landmark, NULL);
		modelpath = (env)->GetStringUTFChars(model, NULL);



		frontal_face_detector detector = get_frontal_face_detector();

		shape_predictor sp;
		deserialize(landmarks) >> sp;
		anet_type net;
		deserialize(modelpath) >> net;

		matrix<rgb_pixel> img;
		matrix<rgb_pixel> img1;
		load_image(img, impath1);
		load_image(img1, impath2);
		image_window win(img);
		image_window win1(img1);
		std::vector<matrix<rgb_pixel>> faces;
		for (auto face : detector(img))
		{
			auto shape = sp(img, face);
			matrix<rgb_pixel> face_chip;
			extract_image_chip(img, get_face_chip_details(shape, 150, 0.25), face_chip);
			faces.push_back(move(face_chip));

			win.add_overlay(face);
		}
		for (auto face1 : detector(img1))
		{
			auto shape1 = sp(img1, face1);
			matrix<rgb_pixel> face_chip1;
			extract_image_chip(img1, get_face_chip_details(shape1, 150, 0.25), face_chip1);
			faces.push_back(move(face_chip1));
	
			win1.add_overlay(face1);
		}

		if (faces.size() == 0)
		{
			cout << "No faces found in image!" << endl;
			return false;
		}

		std::vector<matrix<float, 0, 1>> face_descriptors = net(faces);
		std::vector<sample_pair> edges;
		for (size_t i = 0; i < face_descriptors.size(); ++i)
		{
			for (size_t j = i + 1; j < face_descriptors.size(); ++j)
			{
				cout << "score: " << length(face_descriptors[i] - face_descriptors[j]) << endl;
				if (length(face_descriptors[i] - face_descriptors[j]) < threshold)
					result = true;
			}
		}
	}
	catch (std::exception& e) {
		std::cout << "Exception caught" << std::endl;
		std::cout << e.what() << std::endl;
	}
	return result;

}

std::vector<matrix<rgb_pixel>> jitter_image(
	const matrix<rgb_pixel>& img
)
{
	thread_local random_cropper cropper;
	cropper.set_chip_dims(150, 150);
	cropper.set_randomly_flip(true);
	cropper.set_max_object_height(0.99999);
	cropper.set_background_crops_fraction(0);
	cropper.set_min_object_height(0.97);
	cropper.set_translate_amount(0.02);
	cropper.set_max_rotation_degrees(3);

	std::vector<mmod_rect> raw_boxes(1), ignored_crop_boxes;
	raw_boxes[0] = shrink_rect(get_rect(img), 3);
	std::vector<matrix<rgb_pixel>> crops;

	matrix<rgb_pixel> temp;
	for (int i = 0; i < 100; ++i)
	{
		cropper(img, raw_boxes, temp, ignored_crop_boxes);
		crops.push_back(move(temp));
	}
	return crops;
}

