Thanks! A slightly easier fix was to edit the math widget source code and add a line to look inside the thead.

diff --git a/www/aptui/js/lib/jquery.tablesorter.widget-math.js b/www/aptui/js/lib/jquery.tablesorter.widget-math.js
index 54962d5..20c460b 100644
--- a/www/aptui/js/lib/jquery.tablesorter.widget-math.js
+++ b/www/aptui/js/lib/jquery.tablesorter.widget-math.js
@@ -129,6 +129,9 @@
 				math.mathType( table, wo, $mathCells, wo.math_priority, dataAttrib );
 
 				// only info tbody cells
+				$mathCells = c.$table.find('.' + c.cssInfoBlock + ', thead').find('[' + dataAttrib + ']');
