This awk scripts helps, but there is a bug in it when a line matches the expression /^[^0-9]|^[0-9]\D/. Since it only hammered a few log entries out of thousands I ignored it.

```
BEGIN {
    numlines=0;
    linesout=0;
}

/^[^0-9]|^[0-9]\D/ {
    lines[numlines] = $0;
    numlines++;
    next;
}

/^[0-9]{4}/ {
    for (i=0; i < numlines; i++) {
	printf " %s", lines[i];
    }
    numlines=0;
    if (linesout > 0) {
	printf "\n%s", $0;
    }
    else {
	printf "%s", $0;
    }
    linesout++;
    next;
}

END {
    for (i=0; i < numlines; i++) {
	printf " %s", lines[i];
    }
    printf "\n";
}
```

