In my case, I used non-default database or an external database and It works for using the after_save_instance, here is my code snippets inside my resources.py class and I override few of the functions below MyClassResource(resources.ModelResource):

def get_or_init_instance(self, instance_loader, row):
        """
        Either fetches an already existing instance or initializes a new one.
        """
        with in_database(settings.APP_LABEL_DB, write=True):
            instance = self.get_instance(instance_loader, row)
            if instance:
                return (instance, False)
            else:
                return (self.init_instance(row), True)

    def save_instance(self, instance, using_transactions=True, dry_run=True):
        """
        Takes care of saving the object to the database.
        Keep in mind that this is done by calling ``instance.save()``, so
        objects are not created in bulk!
        """
        with in_database(settings.APP_LABEL_DB, write=True):
            self.before_save_instance(instance, using_transactions, dry_run)
            if not using_transactions and dry_run:
                # we don't have transactions and we want to do a dry_run
                pass

            self.after_save_instance(instance, using_transactions, dry_run)

    def after_save_instance(self, instance, using_transactions, dry_run):
        """
        Override to add additional logic. Does nothing by default.
        """
        if not dry_run:
            instance.save()

